import { useState } from 'react';
import { useAuth } from '../lib/AuthContext';
import { api } from '../lib/api';

const TRUCK_BG = "data:image/jpeg;base64,";

const InterlandLogo = () => (
  <svg viewBox="0 0 420 110" xmlns="http://www.w3.org/2000/svg" style={{ width: '100%', maxWidth: 380 }}>
    <rect x="0" y="18" width="38" height="7" rx="2" fill="#00AEEF" opacity="0.85"/>
    <rect x="0" y="30" width="24" height="5" rx="2" fill="#00AEEF" opacity="0.55"/>
    <rect x="0" y="41" width="16" height="4" rx="2" fill="#00AEEF" opacity="0.35"/>
    <text x="46" y="52" fontFamily="'Arial Black', Arial, sans-serif" fontWeight="900" fontSize="46" fill="#00AEEF" fontStyle="italic" letterSpacing="-1">INTERLAND</text>
    <text x="46" y="88" fontFamily="'Arial Black', Arial, sans-serif" fontWeight="900" fontSize="38" fill="#00AEEF" fontStyle="italic" letterSpacing="1">DISTRIBUTION</text>
    <text x="48" y="106" fontFamily="Arial, sans-serif" fontWeight="400" fontSize="13" fill="rgba(255,255,255,0.85)" letterSpacing="3.5">INTEGRATED LINEHAUL SOLUTIONS</text>
  </svg>
);

export default function Login() {
  const { login } = useAuth();
  const [mode, setMode] = useState('login');
  const [form, setForm] = useState({ username: '', password: '' });
  const [changeForm, setChangeForm] = useState({ current: '', newPass: '', confirm: '' });
  const [forgotUsername, setForgotUsername] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const [tempPassword, setTempPassword] = useState('');
  const [firstLoginUser, setFirstLoginUser] = useState(null);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      const user = await login(form.username, form.password);
      if (user?.first_login) { setFirstLoginUser(user); setMode('change'); }
    } catch (err) {
      setError(err.message || 'Login failed');
    } finally { setLoading(false); }
  };

  const handleForgot = async (e) => {
    e.preventDefault();
    setError(''); setSuccess(''); setLoading(true);
    try {
      const res = await api.forgotPassword({ username: forgotUsername });
      if (res.temp_password) {
        setTempPassword(res.temp_password);
        setSuccess('Temporary password generated. Note it below and use it to login.');
      } else { setSuccess(res.message); }
    } catch (err) {
      setError(err.message || 'Failed to reset password');
    } finally { setLoading(false); }
  };

  const handleChangePassword = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);
    if (changeForm.newPass.length < 8) { setError('New password must be at least 8 characters'); setLoading(false); return; }
    if (changeForm.newPass !== changeForm.confirm) { setError('Passwords do not match'); setLoading(false); return; }
    try {
      await api.changePassword({ current_password: changeForm.current, new_password: changeForm.newPass });
      setSuccess('Password changed! Logging you in...');
      setTimeout(() => setMode('login'), 1500);
    } catch (err) {
      setError(err.message || 'Failed to change password');
    } finally { setLoading(false); }
  };

  const inputStyle = { width: '100%', padding: '11px 13px', fontSize: 14, border: '1px solid #ddd', borderRadius: 6, fontFamily: 'inherit', boxSizing: 'border-box', outline: 'none', background: '#f9f9f9', color: '#222' };
  const labelStyle = { fontSize: 11, color: '#666', display: 'block', marginBottom: 5, textTransform: 'uppercase', letterSpacing: '0.07em', fontWeight: 600 };
  const btnStyle = { width: '100%', padding: '12px', fontSize: 14, fontWeight: 700, border: 'none', borderRadius: 6, background: '#00AEEF', color: 'white', cursor: 'pointer', marginTop: 8 };

  return (
    <div style={{
      minHeight: '100vh', display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center',
      backgroundImage: `url("${TRUCK_BG}")`,
      backgroundSize: 'cover', backgroundPosition: 'center',
      position: 'relative', overflow: 'hidden', padding: '20px 16px',
    }}>
      <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(160deg, rgba(0,31,63,0.72) 0%, rgba(0,61,122,0.65) 40%, rgba(0,90,142,0.58) 70%, rgba(0,174,239,0.45) 100%)' }} />

      <div style={{ position: 'relative', zIndex: 1, marginBottom: 24, width: '100%', maxWidth: 400, textAlign: 'center' }}>
        <InterlandLogo />
      </div>

      <div style={{ position: 'relative', zIndex: 1, background: 'white', borderRadius: 12, padding: '36px 32px', width: '100%', maxWidth: 400, boxShadow: '0 20px 60px rgba(0,0,0,0.45)' }}>

        {mode === 'login' && (
          <form onSubmit={handleLogin}>
            {error && <div style={{ color: '#e53e3e', fontSize: 13, marginBottom: 14, textAlign: 'center', background: '#fff5f5', padding: '8px 12px', borderRadius: 6, border: '1px solid #fed7d7' }}>{error}</div>}
            <div style={{ marginBottom: 14 }}>
              <label style={labelStyle}>Username</label>
              <input style={inputStyle} type="text" required autoFocus value={form.username} onChange={e => setForm(f => ({ ...f, username: e.target.value }))} placeholder="Enter your username" />
            </div>
            <div style={{ marginBottom: 20 }}>
              <label style={labelStyle}>Password</label>
              <input style={inputStyle} type="password" required value={form.password} onChange={e => setForm(f => ({ ...f, password: e.target.value }))} placeholder="Enter your password" />
            </div>
            <button type="submit" style={btnStyle} disabled={loading}>{loading ? 'Signing in...' : 'Sign In'}</button>
            <div style={{ textAlign: 'center', marginTop: 16 }}>
              <button type="button" onClick={() => { setMode('forgot'); setError(''); setSuccess(''); }} style={{ background: 'none', border: 'none', color: '#00AEEF', cursor: 'pointer', fontSize: 13 }}>Forgot password?</button>
            </div>
          </form>
        )}

        {mode === 'forgot' && (
          <form onSubmit={handleForgot}>
            <p style={{ fontSize: 13, color: '#666', marginBottom: 16, textAlign: 'center' }}>Enter your username to get a temporary password.</p>
            {error && <div style={{ color: '#e53e3e', fontSize: 13, marginBottom: 12, textAlign: 'center' }}>{error}</div>}
            {success && <div style={{ background: '#f0fdf4', border: '1px solid #86efac', color: '#059669', padding: '10px 12px', borderRadius: 6, fontSize: 13, marginBottom: 12 }}>{success}</div>}
            {tempPassword && (
              <div style={{ background: '#fffbeb', border: '2px solid #00AEEF', borderRadius: 6, padding: 14, marginBottom: 12, textAlign: 'center' }}>
                <div style={{ fontSize: 11, color: '#666', marginBottom: 4, textTransform: 'uppercase', letterSpacing: '0.06em' }}>Temporary password</div>
                <div style={{ fontSize: 22, fontWeight: 700, fontFamily: 'monospace', color: '#003d7a', letterSpacing: '0.1em' }}>{tempPassword}</div>
                <div style={{ fontSize: 11, color: '#666', marginTop: 4 }}>Use this to login - you will be asked to change it</div>
              </div>
            )}
            <div style={{ marginBottom: 16 }}>
              <label style={labelStyle}>Username</label>
              <input style={inputStyle} type="text" required autoFocus value={forgotUsername} onChange={e => setForgotUsername(e.target.value)} placeholder="Enter your username" />
            </div>
            <button type="submit" style={btnStyle} disabled={loading}>{loading ? 'Generating...' : 'Get Temporary Password'}</button>
            <div style={{ textAlign: 'center', marginTop: 14 }}>
              <button type="button" onClick={() => { setMode('login'); setError(''); setSuccess(''); setTempPassword(''); }} style={{ background: 'none', border: 'none', color: '#00AEEF', cursor: 'pointer', fontSize: 13 }}>Back to login</button>
            </div>
          </form>
        )}

        {mode === 'change' && (
          <form onSubmit={handleChangePassword}>
            <div style={{ background: '#fffbeb', border: '1px solid #00AEEF', borderRadius: 6, padding: 12, marginBottom: 20, fontSize: 13, color: '#003d7a', textAlign: 'center' }}>
              Welcome{firstLoginUser?.name ? `, ${firstLoginUser.name}` : ''}! Please set a new password to continue.
            </div>
            {error && <div style={{ color: '#e53e3e', fontSize: 13, marginBottom: 12, textAlign: 'center' }}>{error}</div>}
            {success && <div style={{ color: '#059669', fontSize: 13, marginBottom: 12, textAlign: 'center' }}>{success}</div>}
            <div style={{ marginBottom: 14 }}>
              <label style={labelStyle}>Current / Temporary Password</label>
              <input style={inputStyle} type="password" required autoFocus value={changeForm.current} onChange={e => setChangeForm(f => ({ ...f, current: e.target.value }))} placeholder="Enter current password" />
            </div>
            <div style={{ marginBottom: 14 }}>
              <label style={labelStyle}>New Password</label>
              <input style={inputStyle} type="password" required value={changeForm.newPass} onChange={e => setChangeForm(f => ({ ...f, newPass: e.target.value }))} placeholder="Minimum 8 characters" />
            </div>
            <div style={{ marginBottom: 20 }}>
              <label style={labelStyle}>Confirm New Password</label>
              <input style={inputStyle} type="password" required value={changeForm.confirm} onChange={e => setChangeForm(f => ({ ...f, confirm: e.target.value }))} placeholder="Repeat new password" />
            </div>
            <button type="submit" style={btnStyle} disabled={loading}>{loading ? 'Saving...' : 'Set New Password'}</button>
          </form>
        )}

        <div style={{ textAlign: 'center', marginTop: 20, fontSize: 11, color: '#aaa' }}>
          Interland Distribution &copy; {new Date().getFullYear()}
        </div>
      </div>
    </div>
  );
}
